import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";
import AIChatbotDevelopmentCompanyServicePage from "@screens/ai-screens/ai-chatbot-development-company";

const AIChatbotDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "AI Chatbot Development Company", link: null },
  ];
  const { data } = props;
  const location = useLocation();
  const fileUrl =
    data?.hire3dDesignerImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const validFaq = data?.allFaqJson?.nodes[0].faqs;

  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "AI Chatbot Development Company offering custom chatbot solutions for websites, apps, and businesses to automate support and improve engagement.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1670",
        },
      },
      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How much does it cost to develop an AI chatbot?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The cost can range from $3,000 to $50,000 or more. It depends on features, design, platform, and how smart the chatbot needs to be.",
            },
          },
          {
            "@type": "Question",
            name: "Which company developed the AI chatbot?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Many companies build AI chatbots, including OpenAI, Google, and Microsoft, each for different uses.",
            },
          },
          {
            "@type": "Question",
            name: "What are the top 3 AI chatbots?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Some of the top AI chatbots are ChatGPT, Google Bard, and Microsoft Copilot, known for smart and fast replies.",
            },
          },
        ],
      },
    ],
  };
  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <AIChatbotDevelopmentCompanyServicePage db={db} faq={validFaq} />
      </main>
    </Layout_v2>
  );
};

export default AIChatbotDevelopmentCompany;
export const queryData = graphql`
  query MyQuery {
    hire3dDesignerImg: file(
      relativePath: { eq: "ai-chatbot-development-company.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "ai-chatbot-development-company" } }) {
      nodes {
        metaTitle
        title
        slug
        description
      }
    }
    allFaqJson(filter: { slug: { eq: "ai-chatbot-development-company" } }) {
      nodes {
        slug
        faqs {
          question
          answer
          status
        }
      }
    }
  }
`;
